import{_ as t,o,c as a,as as n}from"./chunks/framework.Cz19ueXu.js";const u=JSON.parse('{"title":"Introduction","description":"","frontmatter":{},"headers":[],"relativePath":"getting-started/index.md","filePath":"getting-started/index.md","lastUpdated":1777280038000}'),i={name:"getting-started/index.md"};function r(s,e,l,c,d,h){return o(),a("div",null,[...e[0]||(e[0]=[n('<h1 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h1><p><strong>vuecs</strong> is a Vue 3 component library focused on three things:</p><ol><li><p><strong>Themeable, layered class resolution.</strong> Every component reads its CSS classes through a four-layer resolution chain (defaults → themes → overrides → instance props), with structured variants and compound variants. You can drop in a Tailwind, Bootstrap v5, or Bootstrap v4 theme — or write your own — without forking the components.</p></li><li><p><strong>Design tokens, runtime palette switching.</strong> Colors, radii, and semantic aliases live in CSS custom properties in <code>@vuecs/design</code>. Switching the primary palette is a one-line call (<code>setPalette({ primary: &#39;green&#39; })</code>) and re-tints every component on the page with no Vue re-render.</p></li><li><p><strong>SSR-safe Nuxt integration.</strong> <code>@vuecs/nuxt</code> wires the palette and color-mode plumbing into Nuxt&#39;s <code>&lt;head&gt;</code> on the server, so first paint matches what the client computes — no FOUC, no hydration mismatch.</p></li></ol><h2 id="why-another-component-library" tabindex="-1">Why another component library? <a class="header-anchor" href="#why-another-component-library" aria-label="Permalink to &quot;Why another component library?&quot;">​</a></h2><p>Most Vue libraries make you pick a CSS framework upfront and bake it in. vuecs treats themes as <strong>data</strong>: a theme is a function returning a class-map, merged in array order against component defaults. That means:</p><ul><li>The same component renders correctly under Bootstrap v5, Bootstrap v4, or Tailwind v4 — pick at consume time.</li><li>Override individual slot classes from <code>app.use(vuecs, { overrides: ... })</code> without touching component source.</li><li>Per-instance overrides via <code>themeClass</code> and <code>themeVariant</code> props for one-off variations.</li></ul><h2 id="what-s-in-the-box" tabindex="-1">What&#39;s in the box <a class="header-anchor" href="#what-s-in-the-box" aria-label="Permalink to &quot;What&#39;s in the box&quot;">​</a></h2><ul><li><strong>Components</strong> — form controls, navigation, pagination, list controls, countdown, gravatar, link, timeago.</li><li><strong>Themes</strong> — <code>@vuecs/theme-tailwind</code>, <code>@vuecs/theme-bootstrap-v5</code>, <code>@vuecs/theme-bootstrap-v4</code>, <code>@vuecs/theme-font-awesome</code>.</li><li><strong>Design tokens</strong> — <code>@vuecs/design</code> ships CSS variables + a runtime palette switcher.</li><li><strong>Nuxt module</strong> — <code>@vuecs/nuxt</code> ships SSR-safe palette + color-mode composables.</li></ul><h2 id="next-steps" tabindex="-1">Next steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next steps&quot;">​</a></h2><ul><li><a href="/getting-started/installation">Installation</a> — install packages and wire the plugin.</li><li><a href="/getting-started/theming">Theming</a> — pick a theme, override slot classes, switch palette at runtime.</li><li><a href="/getting-started/dark-mode">Dark Mode</a> — toggle <code>.dark</code> and let the design tokens flip everything.</li><li><a href="/components/">Components</a> — browse the component catalog with live demos.</li></ul>',10)])])}const m=t(i,[["render",r]]);export{u as __pageData,m as default};
